INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 46, 100301, 2, 12, 163, "早見沙織", "読書、乗馬、お茶", "トゥインクルウィッシュ", 0, "レイ", "魔族", 18, "クールで何事にも真っ直ぐな剣士", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "B");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 27, 100401, 5, 10, 128, "諸星すみれ", "いたずら、探検", "リトルリリカル", 0, "ミソギ", "ヒューマン", 9, "探検好きのイタズラっ子", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "O");
