INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 32, 100701, 7, 23, 130, "雨宮天", "プリンを食べること", "悪魔偽王国軍（ディアボロス）", 0, "ミヤコ", "魔族", 14, "プリン大好きゴースト娘", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "B");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 40, 100801, 15, 10, 150, "大空直美", "鏡で自分を見ること", "ヴァイスフリューゲル　ランドソル支部", 0, "ユキ", "エルフ", 14, "ボクは誰よりも美しい", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "AB");
