INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 42, 101001, 10, 22, 155, "内田真礼", "空想、ぬいぐるみ集め", "自警団（カォン）", 0, "マホ", "獣人族", 16, "マホマホ王国のプリンセス", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "O");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 44, 101101, 3, 25, 156, "阿澄佳奈", "お裁縫", "ラビリンス", 0, "リノ", "ヒューマン", 15, "人懐っこくてマシンガントークな妹系少女", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "A");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 46, 101201, 6, 24, 156, "大橋彩香", "妹と遊ぶこと、二度寝、昼寝、早寝", "フォレスティエ", 0, "ハツネ", "エルフ", 17, "みんなのために超能力を使う眠り姫", "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "A");
