INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 21, 102001, 5, 3, 117, "日高里菜", "かわいいもの集め", "リトルリリカル", 0, "ミミ", "獣人族", 10, "お歌もにんじんも、ウサギさんも大好き♪", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "O");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 40, 102101, 9, 9, 150, "植田佳奈", "観劇、おままごと", "サレンディア救護院", 0, "クルミ", "ヒューマン", 12, "泣き虫で臆病な守ってあげたい女の子", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "B");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 40, 102201, 7, 22, 150, "原紗友里", "ゲーム全般", "悪魔偽王国軍（ディアボロス）", 0, "ヨリ", "魔族", 13, "人見知りであまのじゃくな女の子", "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "O");
