INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 48, 104601, 12, 1, 158, "沼倉愛美", "猫とたわむれること", "メルクリウス財団", 0, "タマキ", "獣人族", 19, "弱きを助け強きをくじく猫娘", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "AB");
