INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 54, 104901, 3, 24, 168, "生天目仁美", "家事全般", "ラビリンス", 0, "シズル", "ヒューマン", 18, "お姉ちゃんがお世話してあげるからねっ！", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "O");
