INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 53, 105101, 13, 7, 166, "三石琴乃", "研究、実験", "トワイライトキャラバン", 0, "ミツキ", "ヒューマン", 27, "実験が趣味の危険な科学者", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "A");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 100, 105201, 11, 14, 150, "徳井青空", "毛繕い、お喋り", "牧場（エリザベスパーク）", 0, "リマ", "獣人族", 17, "乙女チックなもふもふアニマル", "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", "A");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 33, 105301, 15, 28, 140, "辻あゆみ", "お菓子屋通い", "ヴァイスフリューゲル　ランドソル支部", 0, "モニカ", "ヒューマン", 17, "見た目も中身もお子ちゃまな異国の軍人", "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "A");
