INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 49, 108001, 12, 11, 163, "田所あずさ", "傭兵などのアルバイト", "メルクリウス財団", 0, "ミフユ（サマー）", "ヒューマン", 20, "仕事も私事も効率優先な傭兵少女", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "O");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 42, 108101, 7, 22, 157, "大坪由佳", "占い", "悪魔偽王国軍（ディアボロス）", 0, "シノブ（ハロウィン）", "魔族", 18, "占いが得意な霊能少女", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "AB");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 32, 108201, 7, 23, 130, "雨宮天", "プリンを食べること", "悪魔偽王国軍（ディアボロス）", 0, "ミヤコ（ハロウィン）", "魔族", 14, "プリン大好きゴースト娘", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "B");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 22, 108301, 14, 3, 120, "久野美咲", "ファッション誌鑑賞、コスメ集め", "ルーセント学院", 0, "ミサキ（ハロウィン）", "魔族", 11, "ちょっとおませな恋に恋する女の子", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "A");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 46, 108401, 4, 3, 163, "福原綾香", "各種楽器", "カルミナ", 0, "チカ（クリスマス）", "ヒューマン", 17, "人々を守るために歌う、唱喚士の少女", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "O");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 40, 108501, 9, 9, 150, "植田佳奈", "観劇、おままごと", "サレンディア救護院", 0, "クルミ（クリスマス）", "ヒューマン", 12, "泣き虫で臆病な守ってあげたい女の子", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "B");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, 38, 108601, 9, 10, 148, "芹澤優", "屋内でできる遊び", "サレンディア救護院", 0, "アヤネ（クリスマス）", "ヒューマン", 14, "ぷうきちといつも一緒！", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "B");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 44, 108701, 2, 27, 155, "東山奈央", "人助け、応援", "トゥインクルウィッシュ", 0, "ヒヨリ（ニューイヤー）", "獣人族", 16, "人助けが大好き！　前向き格闘娘", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "A");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 47, 108801, 2, 5, 158, "種田梨沙", "料理、人間観察", "トゥインクルウィッシュ", 0, "ユイ（ニューイヤー）", "ヒューマン", 17, "戦闘のサポートが得意な、心優しい少女", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "O");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 46, 108901, 2, 12, 163, "早見沙織", "読書、乗馬、お茶", "トゥインクルウィッシュ", 0, "レイ（ニューイヤー）", "魔族", 18, "クールで何事にも真っ直ぐな剣士", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "B");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 43, 109001, 13, 30, 154, "橋本ちなみ", "実験、裁縫、料理", "トワイライトキャラバン", 0, "エリコ（バレンタイン）", "魔族", 16, "運命の相手に一途すぎる乙女", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "B");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 54, 109101, 3, 24, 168, "生天目仁美", "家事全般", "ラビリンス", 0, "シズル（バレンタイン）", "ヒューマン", 18, "お姉ちゃんがお世話してあげるからねっ！", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "O");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 55, 109201, "", 1, 156, "日笠陽子", "読書", "？？？", 0, "アン", "ヒューマン", 17, "英霊と契約を結んだマナリアの天才王女", "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", "AB");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 45, 109301, "", 4, 144, "こやまきみこ", "食べること、眠ること", "？？？", 0, "ルゥ", "ヒューマン", 16, "マナリア魔法学院の新入生", "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", "O");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 67, 109401, "", 3, 167, "福原綾香", "ピアノ", "？？？", 0, "グレア", "半人半竜", 17, "人を超越した力を有す心優しい竜姫", "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", "B");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 49, 109501, 15, 19, 157, "長妻樹里", "小説を読むこと", "ヴァイスフリューゲル　ランドソル支部", 0, "クウカ（オーエド）", "ヒューマン", 18, "妄想大好き！　ほんとは照れ屋な女の子", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "AB");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 51, 109601, 15, 31, 163, "佐藤聡美", "忍法開発", "ヴァイスフリューゲル　ランドソル支部", 0, "ニノン（オーエド）", "ヒューマン", 16, "トーゴクの神秘、オシエテクダサイ！", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "O");
